import re
import numpy as np

# Normalization functions
arabic_diacritics = re.compile(r'[\u064b-\u065f\u0670\u06d6-\u06ed]')
tatweel = re.compile(r'[\u0640]')
punct = re.compile(r'[^\w\s\u0600-\u06FF]')  # keep Arabic letters and digits?
# Instead of removing digits, we can remove all punctuation only
punct2 = re.compile(r'[^\u0600-\u06FF\s]')

def normalize_ar(s):
    if not s:
        return ""
    s = str(s)
    # Remove diacritics
    s = arabic_diacritics.sub('', s)
    # Normalize Arabic letters
    s = s.replace('أ','ا').replace('إ','ا').replace('آ','ا')
    s = s.replace('ؤ','و').replace('ئ','ي').replace('ة','ه').replace('ى','ي')
    # Remove tatweel
    s = tatweel.sub('', s)
    # Remove punctuation (non-arabic)
    s = punct2.sub(' ', s)
    # Collapse spaces
    s = re.sub(r'\s+', ' ', s).strip()
    # Lowercase does not matter for arabic; but we can keep
    return s

def tokens(s):
    return normalize_ar(s).split()

def token_f1(a, b):
    ta, tb = tokens(a), tokens(b)
    if not ta or not tb:
        return 0.0
    from collections import Counter
    ca, cb = Counter(ta), Counter(tb)
    overlap = sum(min(ca[t], cb[t]) for t in set(ca) | set(cb))
    prec = overlap / len(ta)
    rec = overlap / len(tb)
    if prec + rec == 0:
        return 0.0
    return 2*prec*rec/(prec+rec)

def lcs_length(a, b):
    # Longest common subsequence length (characters) after normalization
    na, nb = normalize_ar(a), normalize_ar(b)
    # We'll compute LCS length using DP in O(n*m) - might be heavy but strings are short.
    n, m = len(na), len(nb)
    dp = [0]*(m+1)
    for i in range(1, n+1):
        prev = 0
        for j in range(1, m+1):
            temp = dp[j]
            if na[i-1] == nb[j-1]:
                dp[j] = prev + 1
            else:
                dp[j] = max(dp[j], dp[j-1])
            prev = temp
    return dp[m], len(na), len(nb)

def lcs_ratio(a, b):
    l, na, nb = lcs_length(a, b)
    if max(na, nb) == 0:
        return 0.0
    return l / max(na, nb)

def longest_common_substring(a, b):
    na, nb = normalize_ar(a), normalize_ar(b)
    n, m = len(na), len(nb)
    dp = [0]*(m+1)
    longest = 0
    for i in range(1, n+1):
        new_dp = [0]*(m+1)
        for j in range(1, m+1):
            if na[i-1] == nb[j-1]:
                new_dp[j] = dp[j-1] + 1
                if new_dp[j] > longest:
                    longest = new_dp[j]
            else:
                new_dp[j] = 0
        dp = new_dp
    return longest, len(na), len(nb)

def lcsstr_ratio(a, b):
    l, na, nb = longest_common_substring(a, b)
    if max(na, nb) == 0:
        return 0.0
    return l / max(na, nb)

def compute_similarity(a, b):
    # combine metrics
    f1 = token_f1(a, b)
    lcsr = lcs_ratio(a, b)
    lcsstrr = lcsstr_ratio(a, b)
    return {'token_f1': f1, 'lcs_ratio': lcsr, 'lcsstr_ratio': lcsstrr, 'avg': (f1 + lcsr + lcsstrr)/3}

orig_span = "وَلَقَدْ عَلِمْنَا الْمُؤْمِنِينَ وَالْمُؤْمِنَاتِ إِذَا قَالُوا لِقَوْمِهِمْ إِن تَلِدُنَّ مِن بَعْدِهِنَّ فَرَجاً كَذَبْنَ فَإِذَا مَلَطَّنَهُنَّ بِالْغَضَبِ زَعَمْنَ حَقّاً وَهُمْ لِقَوْلِهِنَّ لَا يَزَالُونَ طَاعِنِينَ"
snippet = "وَلَقَدْ ع...طَاعِنِينَ"
